# security/parse_findings.py
"""
Aggregate SAST/DAST findings and enforce severity thresholds.
Exit code 1 if any HIGH/CRITICAL findings exist.
"""
import json
import sys
from pathlib import Path

SEVERITY_ORDER = {"CRITICAL": 4, "HIGH": 3, "MEDIUM": 2, "LOW": 1, "INFO": 0}
BLOCK_THRESHOLD = "HIGH"  # block CI on HIGH and above

def load_bandit(path: str) -> list[dict]:
    data = json.loads(Path(path).read_text())
    return [
        {
            "tool": "bandit",
            "severity": r["issue_severity"].upper(),
            "message": r["issue_text"],
            "file": r["filename"],
            "line": r["line_number"],
        }
        for r in data.get("results", [])
    ]

def load_semgrep(path: str) -> list[dict]:
    data = json.loads(Path(path).read_text())
    return [
        {
            "tool": "semgrep",
            "severity": r["extra"]["severity"].upper(),
            "message": r["extra"]["message"],
            "file": r["path"],
            "line": r["start"]["line"],
        }
        for r in data.get("results", [])
    ]

def check_threshold(findings: list[dict]) -> int:
    blocking = [
        f for f in findings
        if SEVERITY_ORDER.get(f["severity"], 0) >= SEVERITY_ORDER[BLOCK_THRESHOLD]
    ]
    for f in findings:
        icon = "🔴" if f["severity"] in ("HIGH", "CRITICAL") else "🟡"
        print(f"{icon} [{f['tool']}] {f['severity']}: {f['message']} ({f['file']}:{f['line']})")
    if blocking:
        print(f"\n{len(blocking)} HIGH/CRITICAL finding(s) — CI blocked.")
        return 1
    print(f"\n{len(findings)} finding(s), none at HIGH/CRITICAL — CI passes.")
    return 0

if __name__ == "__main__":
    findings = []
    for path in sys.argv[1:]:
        if "bandit" in path:
            findings.extend(load_bandit(path))
        elif "semgrep" in path:
            findings.extend(load_semgrep(path))
    sys.exit(check_threshold(findings))
